// ---- DESIGN (OOD) problems --------------------------------------------
// Each: designSpec + a `factory(...ctorArgs)` JS reference returning an object
// whose methods mirror the spec, plus sample/generated operation sequences.
export const RW_DESIGN_PROBLEMS = [
  {
    kind: 'design',
    slug: 'design-bank-system',
    title: 'Design a Bank System',
    track: 'real-world',
    topic: 'design',
    difficulty: 'medium',
    companyTags: ['stripe-style', 'amazon-style'],
    categoryTags: ['design', 'hashmap'],
    hints: [
      'A hash map from account id to balance is enough to track state.',
      'Every operation must first validate that the account(s) exist.',
      'A transfer succeeds only if the source exists, the destination exists, and the source has enough balance.',
    ],
    statementMd:
      'Design a simple bank.\n\n- `open(id)` — open an account with the given id and balance `0`. Opening an existing id has no effect.\n- `deposit(id, amount)` — add `amount` to the account; return `true` if the account exists, else `false`.\n- `transfer(from, to, amount)` — move `amount` from one account to another; return `true` only if both accounts exist and `from` has at least `amount`, else `false`.\n- `balance(id)` — return the account balance, or `-1` if it does not exist.',
    constraintsMd: '- `1 <= number of operations <= 10^4`\n- `0 <= amount <= 10^9`',
    designSpec: {
      className: 'BankSystem',
      constructorParams: [],
      methods: [
        { name: 'open', params: [{ name: 'id', type: 'int' }], returnType: 'void' },
        { name: 'deposit', params: [{ name: 'id', type: 'int' }, { name: 'amount', type: 'long' }], returnType: 'bool' },
        { name: 'transfer', params: [{ name: 'from', type: 'int' }, { name: 'to', type: 'int' }, { name: 'amount', type: 'long' }], returnType: 'bool' },
        { name: 'balance', params: [{ name: 'id', type: 'int' }], returnType: 'long' },
      ],
    },
    factory: () => {
      const acc = new Map();
      return {
        open: (id) => { if (!acc.has(id)) acc.set(id, 0); },
        deposit: (id, amount) => { if (!acc.has(id)) return false; acc.set(id, acc.get(id) + amount); return true; },
        transfer: (from, to, amount) => {
          if (!acc.has(from) || !acc.has(to)) return false;
          if (acc.get(from) < amount) return false;
          acc.set(from, acc.get(from) - amount);
          acc.set(to, acc.get(to) + amount);
          return true;
        },
        balance: (id) => (acc.has(id) ? acc.get(id) : -1),
      };
    },
    samples: [
      { ctorArgs: [], ops: [
        { name: 'open', args: [1] }, { name: 'open', args: [2] }, { name: 'deposit', args: [1, 100] },
        { name: 'transfer', args: [1, 2, 30] }, { name: 'balance', args: [1] }, { name: 'balance', args: [2] },
      ] },
    ],
    opGenerators: [
      (r) => {
        const ops = [];
        const ids = [1, 2, 3];
        const n = randInt(r, 4, 12);
        for (let i = 0; i < n; i += 1) {
          const pick = randInt(r, 0, 3);
          if (pick === 0) ops.push({ name: 'open', args: [ids[randInt(r, 0, 2)]] });
          else if (pick === 1) ops.push({ name: 'deposit', args: [ids[randInt(r, 0, 2)], randInt(r, 0, 200)] });
          else if (pick === 2) ops.push({ name: 'transfer', args: [ids[randInt(r, 0, 2)], ids[randInt(r, 0, 2)], randInt(r, 0, 150)] });
          else ops.push({ name: 'balance', args: [ids[randInt(r, 0, 2)]] });
        }
        return { ctorArgs: [], ops };
      },
    ],
    hiddenCount: 25,
  },
  {
    kind: 'design',
    slug: 'design-lru-cache',
    title: 'Design an LRU Cache',
    track: 'real-world',
    topic: 'design',
    difficulty: 'medium',
    companyTags: ['amazon-style'],
    categoryTags: ['design', 'hashmap', 'linked-list'],
    hints: [
      'You need O(1) lookup and O(1) recency updates.',
      'Insertion-ordered maps make "least recently used" the first key.',
      'Both get and put count as a use — move the key to most-recently-used.',
    ],
    statementMd:
      'Design a cache with a fixed `capacity` that evicts the least recently used entry.\n\n- `get(key)` — return the value for `key`, or `-1` if absent. A successful get counts as a use.\n- `put(key, value)` — insert or update. If the cache is over capacity, evict the least recently used key. A put counts as a use.',
    constraintsMd: '- `1 <= capacity <= 10^4`\n- `1 <= number of operations <= 10^4`',
    designSpec: {
      className: 'LRUCache',
      constructorParams: [{ name: 'capacity', type: 'int' }],
      methods: [
        { name: 'get', params: [{ name: 'key', type: 'int' }], returnType: 'int' },
        { name: 'put', params: [{ name: 'key', type: 'int' }, { name: 'value', type: 'int' }], returnType: 'void' },
      ],
    },
    factory: (capacity) => {
      const map = new Map();
      return {
        get: (key) => {
          if (!map.has(key)) return -1;
          const v = map.get(key);
          map.delete(key);
          map.set(key, v);
          return v;
        },
        put: (key, value) => {
          if (map.has(key)) map.delete(key);
          map.set(key, value);
          if (map.size > capacity) map.delete(map.keys().next().value);
        },
      };
    },
    samples: [
      { ctorArgs: [2], ops: [
        { name: 'put', args: [1, 10] }, { name: 'put', args: [2, 20] }, { name: 'get', args: [1] },
        { name: 'put', args: [3, 30] }, { name: 'get', args: [2] }, { name: 'get', args: [3] },
      ] },
    ],
    opGenerators: [
      (r) => {
        const cap = randInt(r, 1, 3);
        const ops = [];
        const n = randInt(r, 5, 14);
        for (let i = 0; i < n; i += 1) {
          if (r() < 0.5) ops.push({ name: 'put', args: [randInt(r, 1, 4), randInt(r, 10, 99)] });
          else ops.push({ name: 'get', args: [randInt(r, 1, 4)] });
        }
        return { ctorArgs: [cap], ops };
      },
    ],
    hiddenCount: 25,
  },
  {
    kind: 'design',
    slug: 'design-rate-limiter',
    title: 'Design a Rate Limiter',
    track: 'real-world',
    topic: 'design',
    difficulty: 'medium',
    companyTags: ['stripe-style'],
    categoryTags: ['design', 'sliding-window', 'queue'],
    hints: [
      'Keep the timestamps of the requests you have accepted.',
      'A request at time t is allowed if fewer than `limit` accepted requests fall in the window (t - window, t].',
      'Only record a timestamp when the request is actually allowed.',
    ],
    statementMd:
      'Design a sliding-window rate limiter constructed with `limit` and `window`.\n\n- `allow(timestamp)` — return `true` if the request is permitted, else `false`. A request at time `t` is allowed when the number of previously-allowed requests with timestamp greater than `t - window` is strictly less than `limit`. Timestamps are non-decreasing. Only allowed requests are recorded.',
    constraintsMd: '- `1 <= limit <= 10^4`\n- `1 <= window <= 10^9`\n- timestamps are non-decreasing',
    designSpec: {
      className: 'RateLimiter',
      constructorParams: [{ name: 'limit', type: 'int' }, { name: 'window', type: 'int' }],
      methods: [
        { name: 'allow', params: [{ name: 'timestamp', type: 'int' }], returnType: 'bool' },
      ],
    },
    factory: (limit, window) => {
      const log = [];
      return {
        allow: (t) => {
          const cutoff = t - window;
          const recent = log.filter((x) => x > cutoff).length;
          if (recent < limit) { log.push(t); return true; }
          return false;
        },
      };
    },
    samples: [
      { ctorArgs: [2, 5], ops: [
        { name: 'allow', args: [1] }, { name: 'allow', args: [2] }, { name: 'allow', args: [3] },
        { name: 'allow', args: [7] }, { name: 'allow', args: [8] },
      ] },
    ],
    opGenerators: [
      (r) => {
        const limit = randInt(r, 1, 3);
        const window = randInt(r, 2, 6);
        let t = randInt(r, 0, 2);
        const ops = [];
        const n = randInt(r, 5, 14);
        for (let i = 0; i < n; i += 1) {
          t += randInt(r, 0, 3);
          ops.push({ name: 'allow', args: [t] });
        }
        return { ctorArgs: [limit, window], ops };
      },
    ],
    hiddenCount: 25,
  },
];
